#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        int a, b, c;
        if (scanf("%d %d %d", &a, &b, &c) != 3) return 0;
        int arr[3] = {a, b, c};
        for (int i = 0; i < 3; ++i) {
            if (arr[i] > 0) {
                printf("Positive\n");
            } else if (arr[i] < 0) {
                printf("Negative\n");
            } else {
                printf("Zero\n");
            }
        }
    }
    return 0;
}

